CREATE OR REPLACE FUNCTION public.accept_correction_and_update_stats(p_match_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_match    match_history%ROWTYPE;
  v_proposal jsonb;
BEGIN
  SELECT * INTO v_match
    FROM match_history
   WHERE id = p_match_id::text
     FOR UPDATE;

  IF v_match.id IS NULL THEN
    RAISE EXCEPTION 'match not found';
  END IF;
  IF v_match.status NOT IN ('disputed', 'pending_reconfirmation') THEN
    RAISE EXCEPTION 'match not in a disputable state (status=%)', v_match.status;
  END IF;
  IF v_match.current_proposal IS NULL THEN
    RAISE EXCEPTION 'no proposal to accept';
  END IF;
  IF auth.uid() <> v_match.pending_action_by THEN
    RAISE EXCEPTION 'only the party owed a response can accept';
  END IF;

  v_proposal := v_match.current_proposal;

  UPDATE match_history SET
    status             = 'confirmed',
    result             = v_proposal->>'result',
    sets               = v_proposal->'sets',
    match_date         = v_proposal->>'match_date',
    venue              = v_proposal->>'venue',
    court              = v_proposal->>'court',
    current_proposal   = NULL,
    proposal_by        = NULL,
    pending_action_by  = NULL,
    dispute_expires_at = NULL,
    confirmed_at       = now()
  WHERE id = p_match_id::text;

  PERFORM bump_stats_for_match(p_match_id);
END;
$function$

CREATE OR REPLACE FUNCTION public.apply_match_outcome(p_match_id text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_submitter_id    uuid;
  v_opponent_id     uuid;
  v_result          text;
  v_match_type      text;
  v_sets            jsonb;
  v_weight          numeric;

  v_sub_rating      int;
  v_opp_rating      int;
  v_sub_count       int;
  v_opp_count       int;
  v_sub_skill       text;
  v_opp_skill       text;
  v_sub_locked      boolean;
  v_opp_locked      boolean;

  v_k_sub           int;
  v_k_opp           int;
  v_expected_sub    numeric;
  v_expected_opp    numeric;
  v_score_sub       numeric;
  v_score_opp       numeric;
  v_new_sub         int;
  v_new_opp         int;
  v_sub_count_new   int;
  v_opp_count_new   int;
  v_sub_skill_new   text;
  v_opp_skill_new   text;
  v_sub_status_new  text;
  v_opp_status_new  text;
begin
  select user_id, opponent_id, result, match_type, sets
    into v_submitter_id, v_opponent_id, v_result, v_match_type, v_sets
    from match_history
   where id = p_match_id;

  if not found then
    raise exception 'apply_match_outcome: match % not found', p_match_id;
  end if;

  if v_opponent_id is null then return; end if;
  if v_match_type is not null and v_match_type <> 'ranked' then return; end if;

  -- Module 7.7 supplement: classify match format and pull weight.
  -- A 0 weight is functionally a no-op for rating but we still update
  -- the counters so the calibration period progresses correctly. (In
  -- practice, weight=0 only happens on corrupted rows the validator
  -- failed to catch.)
  v_weight := public._match_format_weight(v_sets);

  perform 1
    from profiles
   where id in (v_submitter_id, v_opponent_id)
   order by id
   for update;

  select coalesce(ranking_points, 1000),
         coalesce(confirmed_ranked_match_count, 0),
         coalesce(skill, ''),
         coalesce(skill_level_locked, false)
    into v_sub_rating, v_sub_count, v_sub_skill, v_sub_locked
    from profiles where id = v_submitter_id;

  select coalesce(ranking_points, 1000),
         coalesce(confirmed_ranked_match_count, 0),
         coalesce(skill, ''),
         coalesce(skill_level_locked, false)
    into v_opp_rating, v_opp_count, v_opp_skill, v_opp_locked
    from profiles where id = v_opponent_id;

  v_k_sub := case
    when v_sub_count >= 5 then 24
    when v_sub_count >= 3 then 32
    else                       40
  end;
  v_k_opp := case
    when v_opp_count >= 5 then 24
    when v_opp_count >= 3 then 32
    else                       40
  end;

  v_expected_sub := 1.0 / (1.0 + power(10.0, (v_opp_rating - v_sub_rating) / 400.0));
  v_expected_opp := 1.0 - v_expected_sub;

  v_score_sub := case when v_result = 'win' then 1.0 else 0.0 end;
  v_score_opp := 1.0 - v_score_sub;

  -- Format weight is applied AFTER expected-score + K (per spec).
  v_new_sub := greatest(0, v_sub_rating + round(v_k_sub * (v_score_sub - v_expected_sub) * v_weight)::int);
  v_new_opp := greatest(0, v_opp_rating + round(v_k_opp * (v_score_opp - v_expected_opp) * v_weight)::int);

  v_sub_count_new := v_sub_count + 1;
  v_opp_count_new := v_opp_count + 1;
  v_sub_status_new := case when v_sub_count_new >= 5 then 'established' else 'provisional' end;
  v_opp_status_new := case when v_opp_count_new >= 5 then 'established' else 'provisional' end;

  v_sub_skill_new := public._derive_displayed_skill(v_new_sub, v_sub_skill);
  v_opp_skill_new := public._derive_displayed_skill(v_new_opp, v_opp_skill);

  update profiles set
    wins                          = wins   + case when v_result = 'win'  then 1 else 0 end,
    losses                        = losses + case when v_result = 'loss' then 1 else 0 end,
    matches_played                = matches_played + 1,
    ranking_points                = v_new_sub,
    confirmed_ranked_match_count  = v_sub_count_new,
    rating_status                 = v_sub_status_new,
    skill                         = v_sub_skill_new,
    skill_level_locked            = v_sub_locked or v_sub_count_new >= 1,
    skill_level_locked_at         = case
      when v_sub_locked then skill_level_locked_at
      when v_sub_count_new >= 1 then now()
      else null
    end
  where id = v_submitter_id;

  update profiles set
    wins                          = wins   + case when v_result = 'loss' then 1 else 0 end,
    losses                        = losses + case when v_result = 'win'  then 1 else 0 end,
    matches_played                = matches_played + 1,
    ranking_points                = v_new_opp,
    confirmed_ranked_match_count  = v_opp_count_new,
    rating_status                 = v_opp_status_new,
    skill                         = v_opp_skill_new,
    skill_level_locked            = v_opp_locked or v_opp_count_new >= 1,
    skill_level_locked_at         = case
      when v_opp_locked then skill_level_locked_at
      when v_opp_count_new >= 1 then now()
      else null
    end
  where id = v_opponent_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.archive_league(p_league_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
  v_owner uuid;
begin
  if session_user <> 'postgres' then
    if uid is null then raise exception 'not authenticated'; end if;
  end if;

  select created_by into v_owner from public.leagues where id = p_league_id;
  if not found then raise exception 'league not found'; end if;

  if session_user <> 'postgres' and v_owner <> uid then
    raise exception 'only the league owner can archive';
  end if;

  update public.leagues
     set status       = 'archived',
         completed_at = now()
   where id = p_league_id;

  insert into public.audit_log(actor_id, action, target_type, target_id, metadata)
  values (uid, 'league_archived', 'league', p_league_id, jsonb_build_object(
    'owner', v_owner
  ));
end; $function$

CREATE OR REPLACE FUNCTION public.audit_tournaments()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_action text;
  v_target uuid;
  v_meta   jsonb;
begin
  if tg_op = 'INSERT' then
    v_action := 'tournament_created';
    v_target := new.id;
    v_meta   := jsonb_build_object(
      'name', new.name,
      'size', new.size,
      'status', new.status
    );
  elsif tg_op = 'UPDATE' then
    v_action := 'tournament_updated';
    v_target := new.id;
    v_meta := jsonb_build_object(
      'before', to_jsonb(old) - '{entrants,draws,results}'::text[],
      'after',  to_jsonb(new) - '{entrants,draws,results}'::text[]
    );
  else -- DELETE
    v_action := 'tournament_deleted';
    v_target := old.id;
    v_meta   := jsonb_build_object('name', old.name, 'size', old.size);
  end if;

  insert into public.audit_log(actor_id, action, target_type, target_id, metadata)
  values (auth.uid(), v_action, 'tournament', v_target, v_meta);

  return coalesce(new, old);
end; $function$

CREATE OR REPLACE FUNCTION public.bump_stats_for_match(p_match_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
  is_party boolean;
begin
  if session_user <> 'postgres' then
    if uid is null then raise exception 'not authenticated'; end if;
    select exists(
      select 1 from public.match_history m
      where m.id = p_match_id::text
        and (m.user_id = uid or m.opponent_id = uid or m.tagged_user_id = uid)
    ) into is_party;
    if not is_party then raise exception 'not a party to this match'; end if;
  end if;
  perform public.apply_match_outcome(p_match_id::text);
end; $function$

CREATE OR REPLACE FUNCTION public.claim_match_invite(p_token text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
declare
  v_uid     uuid := auth.uid();
  v_hash    text;
  v_inv     match_invites%rowtype;
  v_match   match_history%rowtype;
begin
  if v_uid is null then
    raise exception 'claim_match_invite: not authenticated';
  end if;
  v_hash := public._hash_invite_token(p_token);

  select * into v_inv from match_invites where token_hash = v_hash for update;
  if v_inv.id is null then
    raise exception 'claim_match_invite: invite not found';
  end if;
  if v_inv.status <> 'pending' then
    raise exception 'claim_match_invite: invite is %', v_inv.status;
  end if;
  if v_inv.expires_at <= now() then
    -- Sweep to expired so subsequent reads see the right state.
    update match_invites set status = 'expired' where id = v_inv.id;
    raise exception 'claim_match_invite: invite expired';
  end if;
  if v_uid = v_inv.invited_by then
    raise exception 'claim_match_invite: cannot claim your own invite';
  end if;

  select * into v_match from match_history where id = v_inv.match_id for update;
  if v_match.id is null then
    raise exception 'claim_match_invite: underlying match not found';
  end if;
  if v_match.opponent_id is not null then
    -- Defensive — should be unreachable if invite hasn't been claimed.
    raise exception 'claim_match_invite: match already has an opponent';
  end if;
  if v_match.status <> 'pending_opponent_claim' then
    raise exception 'claim_match_invite: match status is %, not pending_opponent_claim', v_match.status;
  end if;

  -- Mark invite claimed
  update match_invites set
    status     = 'claimed',
    claimed_by = v_uid,
    claimed_at = now()
  where id = v_inv.id;

  -- Promote the match to pending_confirmation. The claimer is now the
  -- opponent. Fresh 72h confirmation window.
  update match_history set
    opponent_id   = v_uid,
    status        = 'pending_confirmation',
    submitted_at  = now(),
    expires_at    = now() + interval '72 hours'
  where id = v_match.id;

  -- Notify the logger via the existing notification pipeline. Reuses
  -- 'match_invite_claimed' (added in this migration's emit_notification
  -- update below).
  begin
    insert into notifications (user_id, type, from_user_id, match_id, entity_id)
    values (v_inv.invited_by, 'match_invite_claimed', v_uid, v_match.id, v_inv.id);
  exception when others then
    -- Notification failure must not block the claim itself.
    null;
  end;

  -- Return the same payload preview returns + a hint that we're now
  -- in pending_confirmation so the page knows to show Confirm / Dispute.
  return jsonb_build_object(
    'status',         'claimed',
    'invite_id',      v_inv.id,
    'match_id',       v_match.id,
    'logger_name',    (select name from profiles where id = v_inv.invited_by),
    'invited_name',   v_inv.invited_name,
    'match_date',     v_match.match_date,
    'sets',           v_match.sets,
    'result',         v_match.result,
    'venue',          v_match.venue,
    'court',          v_match.court,
    'next_status',    'pending_confirmation'
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.cleanup_challenge_notifications()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  target_id uuid;
begin
  if tg_op = 'DELETE' then
    target_id := old.id;
  else
    if new.status is distinct from old.status
       and new.status in ('declined', 'expired', 'cancelled', 'converted', 'completed') then
      target_id := new.id;
    else
      return new;
    end if;
  end if;

  delete from public.notifications
  where entity_id = target_id
    and type in (
      'challenge_received',
      'challenge_accepted',
      'challenge_declined',
      'challenge_expired'
    );

  return coalesce(new, old);
end; $function$

CREATE OR REPLACE FUNCTION public.cleanup_league_invite_notifications()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  target_league uuid;
  target_user uuid;
begin
  if tg_op = 'DELETE' then
    target_league := old.league_id;
    target_user   := old.user_id;
  else
    if new.status is distinct from old.status
       and new.status in ('removed', 'declined', 'left') then
      target_league := new.league_id;
      target_user   := new.user_id;
    else
      return new;
    end if;
  end if;

  delete from public.notifications
  where user_id   = target_user
    and entity_id = target_league
    and type in ('league_invite');

  return coalesce(new, old);
end; $function$

CREATE OR REPLACE FUNCTION public.cleanup_match_notifications()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  target_id text;
  is_terminal boolean;
begin
  if (tg_op = 'DELETE') then
    target_id := old.id;
    is_terminal := true;
  else
    target_id := new.id;
    is_terminal := new.status in ('voided','expired','deleted');
    if not is_terminal then
      return coalesce(new, old);
    end if;
  end if;

  delete from public.notifications
  where match_id::text = target_id
    and type in (
      'match_tag',
      'match_confirmed',
      'match_disputed',
      'match_corrected',
      'match_correction_requested',
      'match_counter_proposed',
      'match_voided',
      'match_expired',
      'match_deleted',
      'match_reminder',
      'casual_match_logged'  -- new in this migration
    );

  return coalesce(new, old);
end; $function$

CREATE OR REPLACE FUNCTION public.confirm_match_and_update_stats(p_match_id text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
  v_status text;
  v_opp uuid;
  v_tagged uuid;
begin
  select status, opponent_id, tagged_user_id
    into v_status, v_opp, v_tagged
    from public.match_history where id::text = p_match_id;
  if not found then raise exception 'Match % not found', p_match_id; end if;

  if session_user <> 'postgres' then
    if uid is null then raise exception 'not authenticated'; end if;
    if uid not in (v_opp, v_tagged) then
      raise exception 'only the opponent or tagged user can confirm this match';
    end if;
  end if;

  if v_status <> 'pending_confirmation' then
    raise exception 'Match % is not pending confirmation (status=%)', p_match_id, v_status;
  end if;

  update public.match_history set status = 'confirmed' where id::text = p_match_id;
  perform public.apply_match_outcome(p_match_id);
end; $function$

CREATE OR REPLACE FUNCTION public.create_league(p_name text, p_description text DEFAULT NULL::text, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date, p_max_members integer DEFAULT NULL::integer, p_match_format text DEFAULT 'best_of_3'::text, p_tiebreak_format text DEFAULT 'standard'::text, p_max_matches_per_opponent integer DEFAULT NULL::integer, p_win_points integer DEFAULT 3, p_loss_points integer DEFAULT 0, p_draw_points integer DEFAULT 0, p_mode text DEFAULT 'ranked'::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid       uuid := auth.uid();
  v_league_id uuid;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'must be signed in to create a league'
      USING ERRCODE = 'insufficient_privilege';
  END IF;
  IF p_name IS NULL OR length(btrim(p_name)) = 0 THEN
    RAISE EXCEPTION 'league name is required'
      USING ERRCODE = 'check_violation';
  END IF;
  IF p_mode NOT IN ('ranked', 'casual') THEN
    RAISE EXCEPTION 'mode must be ''ranked'' or ''casual'' (got %)', p_mode
      USING ERRCODE = 'check_violation';
  END IF;

  INSERT INTO public.leagues (
    name, description, created_by,
    start_date, end_date, max_members,
    match_format, tiebreak_format, max_matches_per_opponent,
    win_points, loss_points, draw_points,
    mode
  )
  VALUES (
    btrim(p_name), p_description, v_uid,
    p_start_date, p_end_date, p_max_members,
    p_match_format, p_tiebreak_format, p_max_matches_per_opponent,
    p_win_points, p_loss_points, p_draw_points,
    p_mode
  )
  RETURNING id INTO v_league_id;

  -- Creator is owner + active automatically. Self-invited.
  INSERT INTO public.league_members (league_id, user_id, role, status, invited_by, joined_at)
  VALUES (v_league_id, v_uid, 'owner', 'active', v_uid, now());

  -- Seed a standings row for the creator (zeroed — no matches yet).
  INSERT INTO public.league_standings (league_id, user_id, rank)
  VALUES (v_league_id, v_uid, 1);

  RETURN v_league_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.create_match_invite(p_match_id text, p_invited_name text, p_invited_contact text DEFAULT NULL::text, p_expires_in_hours integer DEFAULT 720)
 RETURNS TABLE(invite_id uuid, token text, expires_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
declare
  v_uid       uuid := auth.uid();
  v_match     match_history%rowtype;
  v_token     text;
  v_hash      text;
  v_id        uuid;
  v_expires   timestamptz;
begin
  if v_uid is null then
    raise exception 'create_match_invite: not authenticated';
  end if;
  if p_invited_name is null or trim(p_invited_name) = '' then
    raise exception 'create_match_invite: invited_name required';
  end if;
  if p_expires_in_hours <= 0 or p_expires_in_hours > 24 * 365 then
    raise exception 'create_match_invite: expires_in_hours out of range';
  end if;

  select * into v_match from match_history where id = p_match_id for update;
  if v_match.id is null then
    raise exception 'create_match_invite: match not found';
  end if;
  if v_match.user_id <> v_uid then
    raise exception 'create_match_invite: only the match logger may invite';
  end if;
  if v_match.opponent_id is not null then
    raise exception 'create_match_invite: match already has a linked opponent';
  end if;
  if v_match.status <> 'pending_opponent_claim' then
    raise exception 'create_match_invite: match status must be pending_opponent_claim (got %)', v_match.status;
  end if;

  -- Revoke any existing pending invite for this match — keeps "at most
  -- one active pending invite" without forcing a unique constraint
  -- (which would fight the soft-revoke history we want to keep).
  update match_invites
     set status = 'revoked', revoked_at = now()
   where match_id = p_match_id and status = 'pending';

  -- Generate fresh 32-byte token; encode base64url (no '+', no '/',
  -- no padding) so it survives URL paths and copy-paste cleanly.
  v_token := translate(encode(extensions.gen_random_bytes(32), 'base64'), '+/', '-_');
  v_token := rtrim(v_token, '=');
  v_hash  := public._hash_invite_token(v_token);
  v_expires := now() + (p_expires_in_hours::text || ' hours')::interval;

  insert into match_invites (match_id, invited_by, invited_name, invited_contact,
                             token_hash, status, expires_at)
  values (p_match_id, v_uid, trim(p_invited_name), nullif(trim(coalesce(p_invited_contact, '')), ''),
          v_hash, 'pending', v_expires)
  returning id into v_id;

  invite_id  := v_id;
  token      := v_token;
  expires_at := v_expires;
  return next;
end;
$function$

CREATE OR REPLACE FUNCTION public.decline_match_invite(p_token text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
declare
  v_uid     uuid := auth.uid();
  v_hash    text;
  v_inv     match_invites%rowtype;
begin
  if v_uid is null then
    raise exception 'decline_match_invite: not authenticated';
  end if;
  v_hash := public._hash_invite_token(p_token);

  select * into v_inv from match_invites where token_hash = v_hash for update;
  if v_inv.id is null then
    raise exception 'decline_match_invite: invite not found';
  end if;
  if v_inv.status <> 'pending' then
    raise exception 'decline_match_invite: invite is %', v_inv.status;
  end if;

  update match_invites set
    status      = 'declined',
    declined_by = v_uid,
    declined_at = now()
  where id = v_inv.id;

  begin
    insert into notifications (user_id, type, from_user_id, match_id, entity_id)
    values (v_inv.invited_by, 'match_invite_declined', v_uid, v_inv.match_id, v_inv.id);
  exception when others then
    null;
  end;
end;
$function$

CREATE OR REPLACE FUNCTION public.emit_notification(p_user_id uuid, p_type text, p_entity_id uuid DEFAULT NULL::uuid, p_metadata jsonb DEFAULT NULL::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
declare
  uid uuid := auth.uid();
  new_id uuid;
  fill_match_id uuid;
  entity_text text := p_entity_id::text;
begin
  if uid is null then raise exception 'not authenticated'; end if;
  if p_user_id = uid then raise exception 'cannot self-notify via emit_notification'; end if;

  if exists (select 1 from public.blocks where blocker_id = p_user_id and blocked_id = uid) then
    return null;
  end if;

  case p_type
    when 'friend_request' then
      if not exists (
        select 1 from public.friend_requests fr
        where fr.sender_id = uid and fr.receiver_id = p_user_id and fr.status = 'pending'
      ) then raise exception 'no pending friend_request for this pair'; end if;

    when 'friend_request_accepted', 'request_accepted' then
      if not exists (
        select 1 from public.friend_requests fr
        where fr.receiver_id = uid and fr.sender_id = p_user_id and fr.status = 'accepted'
      ) then raise exception 'no accepted friend_request'; end if;

    when 'message_request' then
      if not exists (
        select 1 from public.conversations c
        where c.id = p_entity_id
          and c.requester_id = uid
          and ((c.user1_id = p_user_id) or (c.user2_id = p_user_id))
      ) then raise exception 'not a valid message_request'; end if;

    when 'message_request_accepted' then
      if not exists (
        select 1 from public.conversations c
        where c.id = p_entity_id
          and c.status = 'accepted'
          and (
            (c.user1_id = uid and c.user2_id = p_user_id) or
            (c.user2_id = uid and c.user1_id = p_user_id)
          )
      ) then raise exception 'not a valid message_request_accepted'; end if;

    when 'challenge_received', 'challenge_accepted', 'challenge_declined', 'challenge_expired' then
      if not exists (
        select 1 from public.challenges ch
        where ch.id = p_entity_id
          and (
            (ch.challenger_id = uid and ch.challenged_id = p_user_id) or
            (ch.challenged_id = uid and ch.challenger_id = p_user_id)
          )
      ) then raise exception 'not a party to this challenge'; end if;

    when 'match_tag', 'match_confirmed', 'match_disputed', 'match_corrected',
         'match_correction_requested', 'match_counter_proposed', 'match_voided',
         'match_expired', 'match_reminder' then
      if not exists (
        select 1 from public.match_history m
        where m.id = entity_text
          and (
            (m.user_id = uid and (m.opponent_id = p_user_id or m.tagged_user_id = p_user_id)) or
            (m.opponent_id = uid and m.user_id = p_user_id) or
            (m.tagged_user_id = uid and m.user_id = p_user_id)
          )
      ) then raise exception 'not a party to this match'; end if;
      fill_match_id := p_entity_id;

    when 'casual_match_logged' then
      -- Tighter standing than match_tag: the recipient MUST be the
      -- opponent_id (not the legacy tagged_user_id). Casual matches
      -- never use the tag flow.
      if not exists (
        select 1 from public.match_history m
        where m.id = entity_text
          and m.user_id = uid
          and m.opponent_id = p_user_id
          and m.match_type = 'casual'
      ) then raise exception 'not a casual match between the caller (submitter) and recipient (opponent)'; end if;
      fill_match_id := p_entity_id;

    when 'match_deleted' then
      fill_match_id := p_entity_id;

    when 'match_invite_claimed', 'match_invite_declined' then
      if not exists (
        select 1 from public.match_invites mi
        where mi.id = p_entity_id
          and mi.invited_by = p_user_id
          and (mi.claimed_by = uid or mi.declined_by = uid)
      ) then raise exception 'not a party to this invite'; end if;

    when 'pact_proposed', 'pact_confirmed', 'pact_booked',
         'pact_cancelled', 'pact_claimed' then
      if not exists (
        select 1 from public.match_pacts mp
        where mp.id = p_entity_id
          and (
            (mp.proposer_id = uid and mp.partner_id = p_user_id) or
            (mp.partner_id = uid and mp.proposer_id = p_user_id)
          )
      ) then raise exception 'not a party to this pact'; end if;

    when 'league_invite', 'league_joined' then
      null;

    else
      raise exception 'unknown notification type: %', p_type;
  end case;

  insert into notifications (user_id, type, from_user_id, match_id, entity_id, metadata)
  values (p_user_id, p_type, uid, fill_match_id::text, p_entity_id, p_metadata)
  returning id into new_id;
  return new_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.get_or_create_conversation(other_id uuid)
 RETURNS SETOF conversations
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  me uuid := auth.uid();
  u1 uuid;
  u2 uuid;
  are_friends boolean;
  initial_status text;
begin
  if me is null then
    raise exception 'Not authenticated';
  end if;
  if other_id is null or other_id = me then
    raise exception 'Invalid other_id';
  end if;

  -- Canonical pair order: user1_id < user2_id by uuid.
  if me < other_id then
    u1 := me; u2 := other_id;
  else
    u1 := other_id; u2 := me;
  end if;

  -- Friendship check
  select exists(
    select 1 from public.friend_requests fr
    where fr.status = 'accepted'
      and (
        (fr.sender_id = me and fr.receiver_id = other_id) or
        (fr.sender_id = other_id and fr.receiver_id = me)
      )
  ) into are_friends;

  initial_status := case when are_friends then 'accepted' else 'pending' end;

  -- Atomic insert, unique index on pair_key deduplicates races.
  insert into public.conversations (user1_id, user2_id, requester_id, status)
  values (u1, u2, me, initial_status)
  on conflict (pair_key) do nothing;

  return query
    select * from public.conversations
    where user1_id = u1 and user2_id = u2
    limit 1;
end;
$function$

CREATE OR REPLACE FUNCTION public.guard_dm_insert_block()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_recipient uuid;
begin
  -- Recipient = the conversation participant who isn't the sender.
  select case when c.user1_id = new.sender_id then c.user2_id else c.user1_id end
    into v_recipient
    from public.conversations c
   where c.id = new.conversation_id;

  if v_recipient is null then
    -- Conversation doesn't exist or is malformed — let the existing
    -- FK / RLS path raise the canonical error.
    return new;
  end if;

  if exists (
    select 1 from public.blocks
     where blocker_id = v_recipient
       and blocked_id = new.sender_id
  ) then
    raise exception 'recipient_has_blocked_sender' using errcode = '42501';
  end if;

  return new;
end; $function$

CREATE OR REPLACE FUNCTION public.invite_to_league(p_league_id uuid, p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_is_owner boolean;
  v_league_status text;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'must be signed in' USING ERRCODE = 'insufficient_privilege';
  END IF;

  SELECT status INTO v_league_status FROM public.leagues WHERE id = p_league_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'league % does not exist', p_league_id;
  END IF;
  IF v_league_status <> 'active' THEN
    RAISE EXCEPTION 'league is not active';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.league_members
    WHERE league_id = p_league_id AND user_id = v_uid AND role = 'owner' AND status = 'active'
  ) INTO v_is_owner;
  IF NOT v_is_owner THEN
    RAISE EXCEPTION 'only the league owner can invite members'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  IF p_user_id = v_uid THEN
    RAISE EXCEPTION 'cannot invite yourself — you are already the owner';
  END IF;

  INSERT INTO public.league_members (league_id, user_id, role, status, invited_by)
  VALUES (p_league_id, p_user_id, 'member', 'invited', v_uid)
  ON CONFLICT (league_id, user_id) DO UPDATE
    SET status     = CASE
                       WHEN league_members.status IN ('declined','removed') THEN 'invited'
                       ELSE league_members.status
                     END,
        invited_by = EXCLUDED.invited_by;

  -- Fire notification (best-effort — not part of transactional guarantees)
  INSERT INTO public.notifications (user_id, type, from_user_id, entity_id)
  VALUES (p_user_id, 'league_invite', v_uid, p_league_id);
END;
$function$

CREATE OR REPLACE FUNCTION public.preview_match_invite(p_token text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
declare
  v_hash    text;
  v_inv     match_invites%rowtype;
  v_match   match_history%rowtype;
  v_logger  text;
  v_status  text;
begin
  if p_token is null or length(p_token) < 16 then
    return jsonb_build_object('status', 'not_found');
  end if;
  v_hash := public._hash_invite_token(p_token);

  select * into v_inv from match_invites where token_hash = v_hash;
  if v_inv.id is null then
    return jsonb_build_object('status', 'not_found');
  end if;

  -- Auto-flag expired pending rows (the cron sweep would do this but
  -- we don't want to wait on it for a request that's looking right now).
  v_status := v_inv.status;
  if v_status = 'pending' and v_inv.expires_at <= now() then
    v_status := 'expired';
  end if;

  if v_status <> 'pending' and v_status <> 'claimed' then
    return jsonb_build_object('status', v_status);
  end if;

  select * into v_match from match_history where id = v_inv.match_id;
  if v_match.id is null then
    return jsonb_build_object('status', 'not_found');
  end if;

  select coalesce(name, 'A CourtSync player') into v_logger
    from profiles where id = v_inv.invited_by;

  return jsonb_build_object(
    'status',         v_status,
    'invite_id',      v_inv.id,
    'match_id',       v_match.id,
    'logger_name',    v_logger,
    'invited_name',   v_inv.invited_name,
    'match_date',     v_match.match_date,
    'sets',           v_match.sets,
    'result',         v_match.result,        -- in submitter's frame; UI flips
    'venue',          v_match.venue,
    'court',          v_match.court,
    'expires_at',     v_inv.expires_at,
    -- For UX: tell the caller whether they're the logger so the page
    -- can render "you logged this — share it" instead of "claim it".
    'caller_is_logger', case when auth.uid() = v_inv.invited_by then true else false end,
    'caller_is_claimer', case when auth.uid() is not null and auth.uid() = v_inv.claimed_by then true else false end
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.propose_match_correction(p_match_id uuid, p_reason_code text, p_reason_detail text, p_proposal jsonb, p_next_status text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_match             match_history%rowtype;
  v_actor             uuid := auth.uid();
  v_user_id           uuid;
  v_opponent_id       uuid;
  v_pending_action_by uuid;
  v_expected_pending  uuid;
  v_revision_number   integer;
  v_action            text;
begin
  -- 1. Auth
  if v_actor is null then
    raise exception 'not authenticated';
  end if;

  -- 2. Validate p_next_status
  if p_next_status not in ('disputed', 'pending_reconfirmation') then
    raise exception 'invalid next status: %', p_next_status;
  end if;

  -- 3. Validate proposal shape
  if p_proposal is null then
    raise exception 'proposal is required';
  end if;
  if (p_proposal->>'result') is null then
    raise exception 'proposal.result is required';
  end if;
  if (p_proposal->'sets') is null then
    raise exception 'proposal.sets is required';
  end if;
  if (p_proposal->>'match_date') is null then
    raise exception 'proposal.match_date is required';
  end if;

  -- 4. Lock the row
  -- id is stored as text; cast p_match_id to text for the WHERE clause
  select *
    into v_match
    from match_history
   where id = p_match_id::text
     for update;

  if v_match.id is null then
    raise exception 'match not found';
  end if;

  -- 5. Participant columns are uuid — assign directly, no cast needed
  v_user_id           := v_match.user_id;
  v_opponent_id       := v_match.opponent_id;
  v_pending_action_by := v_match.pending_action_by;

  -- 6. Caller must be one of the two parties
  if v_actor not in (v_user_id, v_opponent_id) then
    raise exception 'only match participants may propose a correction';
  end if;

  -- 7. Reject casual / untagged matches
  if v_opponent_id is null then
    raise exception 'cannot dispute an untagged / casual match';
  end if;

  -- 8. State-machine: branch on CURRENT status
  if v_match.status = 'pending_confirmation' then
    if v_actor <> v_opponent_id then
      raise exception 'only the tagged opponent may open a dispute';
    end if;
    if p_next_status <> 'disputed' then
      raise exception 'opening a dispute must use next_status=disputed';
    end if;
    v_expected_pending := v_user_id;
    v_action           := 'disputed';

  elsif v_match.status in ('disputed', 'pending_reconfirmation') then
    if v_pending_action_by is null then
      raise exception 'pending_action_by is missing on an active dispute';
    end if;
    if v_actor <> v_pending_action_by then
      raise exception 'only the party owed a response may counter-propose';
    end if;
    v_expected_pending := case
      when v_actor = v_user_id then v_opponent_id
      else v_user_id
    end;
    v_action := 'counter_proposed';

  else
    raise exception 'cannot propose a correction from status: %', v_match.status;
  end if;

  -- 9. Increment revision count
  v_revision_number := coalesce(v_match.revision_count, 0) + 1;

  -- 10. Write match_history
  -- id is text: cast p_match_id to text in the WHERE clause
  update match_history set
    status                = p_next_status,
    dispute_raised_by     = v_actor,
    dispute_reason_code   = p_reason_code,
    dispute_reason_detail = nullif(p_reason_detail, ''),
    current_proposal      = p_proposal,
    proposal_by           = v_actor,
    pending_action_by     = v_expected_pending,
    revision_count        = v_revision_number,
    dispute_expires_at    = now() + interval '48 hours'
  where id = p_match_id::text;

  -- 11. Insert revision history
  insert into match_revisions (
    match_id,
    revision_number,
    changed_by,
    action,
    snapshot_before,
    snapshot_after,
    reason_code,
    reason_detail
  ) values (
    p_match_id::text,
    v_revision_number,
    v_actor,
    v_action,
    jsonb_build_object(
      'result',     v_match.result,
      'sets',       v_match.sets,
      'match_date', v_match.match_date,
      'venue',      v_match.venue,
      'court',      v_match.court
    ),
    p_proposal,
    p_reason_code,
    nullif(p_reason_detail, '')
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.recalc_league_standings_on_match_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- DELETE → OLD has the league; INSERT → NEW has it; UPDATE → either/both.
  -- Always recompute the affected league(s). Idempotent so it's safe to
  -- run multiple times; early-returns inside recalc when nothing eligible.
  IF TG_OP = 'DELETE' THEN
    IF OLD.league_id IS NOT NULL THEN
      PERFORM public.recalculate_league_standings(OLD.league_id);
    END IF;
    RETURN OLD;
  END IF;

  IF NEW.league_id IS NOT NULL THEN
    PERFORM public.recalculate_league_standings(NEW.league_id);
  END IF;
  IF TG_OP = 'UPDATE'
     AND OLD.league_id IS NOT NULL
     AND OLD.league_id IS DISTINCT FROM NEW.league_id THEN
    -- Shouldn't happen (validate_match_league rejects it) but defence-in-depth.
    PERFORM public.recalculate_league_standings(OLD.league_id);
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.recalculate_league_standings(p_league_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
begin
  if session_user <> 'postgres' then
    if uid is null then raise exception 'not authenticated'; end if;
    if not public._is_league_member(p_league_id, uid) then
      raise exception 'not a league member';
    end if;
  end if;
  perform public.recalculate_league_standings_inner(p_league_id);
end; $function$

CREATE OR REPLACE FUNCTION public.remove_league_member(p_league_id uuid, p_user_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
  v_owner uuid;
begin
  if session_user <> 'postgres' then
    if uid is null then raise exception 'not authenticated'; end if;
  end if;

  select created_by into v_owner from public.leagues where id = p_league_id;
  if not found then raise exception 'league not found'; end if;

  if session_user <> 'postgres' and v_owner <> uid and p_user_id <> uid then
    raise exception 'only the league owner can remove other members';
  end if;

  update public.league_members
     set status = 'removed'
   where league_id = p_league_id
     and user_id   = p_user_id;

  perform public.recalculate_league_standings_inner(p_league_id);

  insert into public.audit_log(actor_id, action, target_type, target_id, metadata)
  values (uid, 'league_member_removed', 'league', p_league_id, jsonb_build_object(
    'removed_user', p_user_id,
    'owner',        v_owner,
    'self_leave',   p_user_id = uid
  ));
end; $function$

CREATE OR REPLACE FUNCTION public.respond_to_league_invite(p_league_id uuid, p_accept boolean)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_member public.league_members%ROWTYPE;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'must be signed in' USING ERRCODE = 'insufficient_privilege';
  END IF;

  SELECT * INTO v_member
  FROM public.league_members
  WHERE league_id = p_league_id AND user_id = v_uid
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'no invitation found';
  END IF;
  IF v_member.status <> 'invited' THEN
    RAISE EXCEPTION 'invitation is no longer pending (status=%)', v_member.status;
  END IF;

  IF p_accept THEN
    UPDATE public.league_members
       SET status = 'active', joined_at = now()
     WHERE id = v_member.id;

    -- Seed zeroed standings row; AFTER trigger on match_history will update
    -- as matches are logged/confirmed.
    INSERT INTO public.league_standings (league_id, user_id, rank)
    VALUES (p_league_id, v_uid, NULL)
    ON CONFLICT (league_id, user_id) DO NOTHING;

    -- Recompute ranks now that a new active member has joined
    PERFORM public.recalculate_league_standings(p_league_id);

    -- Notify other active members that someone joined
    INSERT INTO public.notifications (user_id, type, from_user_id, entity_id)
    SELECT lm.user_id, 'league_joined', v_uid, p_league_id
    FROM public.league_members lm
    WHERE lm.league_id = p_league_id
      AND lm.status = 'active'
      AND lm.user_id <> v_uid;
  ELSE
    UPDATE public.league_members
       SET status = 'declined'
     WHERE id = v_member.id;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.respond_to_match_tag(p_match_id text, p_accept boolean)
 RETURNS match_history
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  v_uid    uuid := auth.uid();
  v_match  public.match_history%rowtype;
  v_row    public.match_history%rowtype;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'respond_to_match_tag: not authenticated';
  END IF;

  SELECT * INTO v_match FROM public.match_history WHERE id = p_match_id FOR UPDATE;
  IF v_match.id IS NULL THEN
    RAISE EXCEPTION 'respond_to_match_tag: match not found';
  END IF;

  -- Only the tagged user (the opponent the submitter named) can respond.
  IF v_match.tagged_user_id IS NULL OR v_match.tagged_user_id <> v_uid THEN
    RAISE EXCEPTION 'respond_to_match_tag: not the tagged user';
  END IF;

  -- Idempotent: don't re-write if the user already responded.
  IF v_match.tag_status IN ('accepted', 'rejected') THEN
    RETURN v_match;
  END IF;

  UPDATE public.match_history
     SET tag_status = CASE WHEN p_accept THEN 'accepted' ELSE 'rejected' END,
         status     = CASE WHEN p_accept THEN 'confirmed' ELSE 'expired' END
   WHERE id = p_match_id
   RETURNING * INTO v_row;
  RETURN v_row;
END;
$function$

CREATE OR REPLACE FUNCTION public.revoke_match_invite(p_invite_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
declare
  v_uid uuid := auth.uid();
  v_inv match_invites%rowtype;
begin
  if v_uid is null then
    raise exception 'revoke_match_invite: not authenticated';
  end if;

  select * into v_inv from match_invites where id = p_invite_id for update;
  if v_inv.id is null then
    raise exception 'revoke_match_invite: invite not found';
  end if;
  if v_inv.invited_by <> v_uid then
    raise exception 'revoke_match_invite: only the inviter can revoke';
  end if;
  if v_inv.status <> 'pending' then
    raise exception 'revoke_match_invite: invite is %', v_inv.status;
  end if;

  update match_invites set
    status     = 'revoked',
    revoked_at = now()
  where id = v_inv.id;
end;
$function$

CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.throttle_match_invites()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF (SELECT count(*) FROM public.match_invites
       WHERE invited_by = NEW.invited_by
         AND created_at > now() - interval '1 minute') >= 10 THEN
    RAISE EXCEPTION 'rate limit: more than 10 match invites per minute';
  END IF;
  IF (SELECT count(*) FROM public.match_invites
       WHERE invited_by = NEW.invited_by
         AND created_at > now() - interval '1 day') >= 100 THEN
    RAISE EXCEPTION 'rate limit: more than 100 match invites per day';
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.upsert_message_notification(p_user_id uuid, p_from_user_id uuid, p_entity_id uuid, p_metadata jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
begin
  if session_user <> 'postgres' then
    if uid is null then raise exception 'not authenticated'; end if;
    if p_from_user_id is distinct from uid then
      raise exception 'p_from_user_id must be auth.uid()';
    end if;
    if p_user_id = uid then
      raise exception 'cannot self-notify';
    end if;
    -- Caller must be a participant of the referenced conversation, and
    -- p_user_id must be the OTHER participant.
    if p_entity_id is null or not exists (
      select 1 from public.conversations c
      where c.id = p_entity_id
        and (
          (c.user1_id = uid and c.user2_id = p_user_id) or
          (c.user2_id = uid and c.user1_id = p_user_id)
        )
    ) then
      raise exception 'not a valid message notification for this conversation';
    end if;
    -- Silent no-op if recipient has blocked the caller.
    if exists (select 1 from public.blocks where blocker_id = p_user_id and blocked_id = uid) then
      return;
    end if;
  end if;

  insert into public.notifications (user_id, type, from_user_id, entity_id, metadata, read, created_at)
  values (p_user_id, 'message', p_from_user_id, p_entity_id, p_metadata, false, now())
  on conflict (user_id, entity_id) where entity_id is not null and type = 'message'
  do update set from_user_id = excluded.from_user_id,
                metadata     = excluded.metadata,
                read         = false,
                created_at   = excluded.created_at;
end; $function$

CREATE OR REPLACE FUNCTION public.validate_match_league()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_league          public.leagues%ROWTYPE;
  v_user_active     boolean;
  v_opp_active      boolean;
  v_existing_count  integer;
BEGIN
  IF NEW.league_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Immutable league_id post-insert
  IF TG_OP = 'UPDATE'
     AND OLD.league_id IS NOT NULL
     AND OLD.league_id IS DISTINCT FROM NEW.league_id THEN
    RAISE EXCEPTION 'league_id is immutable once set on a match (match %)', NEW.id
      USING ERRCODE = 'check_violation';
  END IF;

  SELECT * INTO v_league FROM public.leagues WHERE id = NEW.league_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'league % does not exist', NEW.league_id
      USING ERRCODE = 'foreign_key_violation';
  END IF;
  IF v_league.status <> 'active' THEN
    RAISE EXCEPTION 'league % is not active (status=%)', v_league.id, v_league.status
      USING ERRCODE = 'check_violation';
  END IF;

  -- ── NEW: match_type must equal league.mode ─────────────────────────────
  -- Was previously hardcoded to 'ranked'. Now compares per-league so a
  -- mode='casual' league accepts only match_type='casual' rows, and a
  -- mode='ranked' league accepts only match_type='ranked' rows.
  IF NEW.match_type IS DISTINCT FROM v_league.mode THEN
    RAISE EXCEPTION
      'league % is mode=% but match was logged as match_type=%',
      v_league.id, v_league.mode, COALESCE(NEW.match_type, 'NULL')
      USING ERRCODE = 'check_violation';
  END IF;

  -- Opponent + both-must-be-active checks (unchanged)
  IF NEW.opponent_id IS NULL THEN
    RAISE EXCEPTION 'league matches must have an opponent_id (match %)', NEW.id
      USING ERRCODE = 'not_null_violation';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.league_members
    WHERE league_id = NEW.league_id AND user_id = NEW.user_id AND status = 'active'
  ) INTO v_user_active;
  IF NOT v_user_active THEN
    RAISE EXCEPTION 'user % is not an active member of league %', NEW.user_id, NEW.league_id
      USING ERRCODE = 'check_violation';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.league_members
    WHERE league_id = NEW.league_id AND user_id = NEW.opponent_id AND status = 'active'
  ) INTO v_opp_active;
  IF NOT v_opp_active THEN
    RAISE EXCEPTION 'opponent % is not an active member of league %', NEW.opponent_id, NEW.league_id
      USING ERRCODE = 'check_violation';
  END IF;

  -- max_matches_per_opponent enforcement (unchanged)
  IF v_league.max_matches_per_opponent IS NOT NULL AND TG_OP = 'INSERT' THEN
    SELECT count(*) INTO v_existing_count
    FROM public.match_history
    WHERE league_id = NEW.league_id
      AND status <> 'voided'
      AND (
        (user_id = NEW.user_id     AND opponent_id = NEW.opponent_id) OR
        (user_id = NEW.opponent_id AND opponent_id = NEW.user_id)
      );
    IF v_existing_count >= v_league.max_matches_per_opponent THEN
      RAISE EXCEPTION
        'league % allows at most % match(es) per opponent pair (already have %)',
        NEW.league_id, v_league.max_matches_per_opponent, v_existing_count
        USING ERRCODE = 'check_violation';
    END IF;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.void_match(p_match_id uuid, p_reason text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
  v_status text;
  v_user uuid;
  v_opp  uuid;
  v_tag  uuid;
begin
  if session_user <> 'postgres' then
    if uid is null then raise exception 'not authenticated'; end if;
  end if;

  select status, user_id, opponent_id, tagged_user_id
    into v_status, v_user, v_opp, v_tag
    from public.match_history
   where id::text = p_match_id::text;

  if not found then
    raise exception 'Match % not found', p_match_id;
  end if;

  if session_user <> 'postgres' and
     uid not in (v_user, v_opp, v_tag) and
     not exists (select 1 from public.profiles p where p.id = uid and p.is_admin)
  then
    raise exception 'not authorized to void this match';
  end if;

  if v_status not in ('pending_confirmation', 'disputed', 'pending_reconfirmation') then
    raise exception 'cannot void match in status %', v_status;
  end if;

  update public.match_history
     set status            = 'voided',
         voided_at         = now(),
         voided_reason     = p_reason,
         current_proposal  = null,
         proposal_by       = null,
         pending_action_by = null
   where id::text = p_match_id::text;

  -- Audit row beyond what the trigger logged — captures the reason text.
  insert into public.audit_log(actor_id, action, target_type, target_id, metadata)
  values (uid, 'void_match_rpc', 'match', p_match_id, jsonb_build_object(
    'reason', p_reason, 'prior_status', v_status
  ));
end; $function$
